mapper.select:
SELECT v.id, v.user_id AS author_uid, v.title, v.cover_url, v.view_count, v.duration, v.create_time, u.nickname FROM t_video v LEFT JOIN t_user_info u ON v.user_id = u.user_id WHERE v.status = 0 AND v.id IN
#{id}
ORDER BY v.create_time DESC, v.id DESC

mapper.update:
UPDATE t_video
SET view_count = IFNULL(view_count, 0) + #{delta}
WHERE id = #{videoId}
  AND status = 0
